    pairs = args[0]
    n = len(pairs) + 1
    if not isinstance(output, list) or len(output) != n:
        return False
    if len(set(output)) != n:
        return False
    got = {}
    for i in range(n - 1):
        a, b = output[i], output[i + 1]
        key = (a, b) if a <= b else (b, a)
        got[key] = got.get(key, 0) + 1
    want = {}
    for u, v in pairs:
        key = (u, v) if u <= v else (v, u)
        want[key] = want.get(key, 0) + 1
    return got == want

