function validate(args, output) {
    const pairs = args[0];
    const n = pairs.length + 1;
    if (!Array.isArray(output) || output.length !== n) return false;
    if (new Set(output).size !== n) return false;
    const got = new Map();
    for (let i = 0; i < n - 1; i++) {
        let a = output[i], b = output[i + 1];
        if (a > b) { const t = a; a = b; b = t; }
        const key = a + ',' + b;
        got.set(key, (got.get(key) || 0) + 1);
    }
    const want = new Map();
    for (const [u0, v0] of pairs) {
        let u = u0, v = v0;
        if (u > v) { const t = u; u = v; v = t; }
        const key = u + ',' + v;
        want.set(key, (want.get(key) || 0) + 1);
    }
    if (got.size !== want.size) return false;
    for (const [k, c] of got) { if (want.get(k) !== c) return false; }
    return true;
}

