class Solution:
    def restoreArray(self, adjacentPairs):
        from collections import defaultdict
        adj = defaultdict(list)
        for u, v in adjacentPairs:
            adj[u].append(v)
            adj[v].append(u)
        start = None
        for k in adj:
            if len(adj[k]) == 1:
                start = k
                break
        res = [start]
        prev = None
        cur = start
        n = len(adjacentPairs) + 1
        while len(res) < n:
            for nxt in adj[cur]:
                if nxt != prev:
                    res.append(nxt)
                    prev, cur = cur, nxt
                    break
        if res[0] > res[-1]:
            res.reverse()
        return res

