var restoreArray = function(adjacentPairs) {
    const adj = new Map();
    const push = (a, b) => { if (!adj.has(a)) adj.set(a, []); adj.get(a).push(b); };
    for (const [u, v] of adjacentPairs) { push(u, v); push(v, u); }
    const n = adjacentPairs.length + 1;
    let start = null;
    for (const [k, lst] of adj) { if (lst.length === 1) { start = k; break; } }
    const res = [start];
    let prev = null, cur = start;
    while (res.length < n) {
        const lst = adj.get(cur);
        const nxt = (lst[0] !== prev) ? lst[0] : lst[1];
        res.push(nxt);
        prev = cur; cur = nxt;
    }
    if (res[0] > res[res.length - 1]) res.reverse();
    return res;
};
